import styleRegistration from "./Registration.module.scss";
import React, { useCallback, useState } from "react";
import InputText from "./inputText/InputText";
import { useSelector, useDispatch } from "react-redux";
import {
  nickNameActin,
  emailActin,
  passwordActin,
  registerActin,
} from "../../redux/register-reducer.ts";
import { useHTTP } from "./../../../hook/http.js";
import ButtonBlock from "./button-block/ButtonBlock";

const Registration = (props) => {
  const [add, setAdd] = useState(true);
  const { request } = useHTTP();
  const state = useSelector((state) => state.register);
  const dispatch = useDispatch();
  const [get, set] = useState();
  const increaseCounter = useCallback(
    (e, a) => {
      let text = e.target.value;
      dispatch(a(text));
      set("");
    },
    [dispatch]
  );

  const toButton = async () => {
    const { nickName, email, password } = state;
    if (nickName === "" || email === "" || password === "") {
      return set("Поля должны быть заполнены");
    }

    const data = {
      nickName: nickName,
      email: email,
      password: password,
    };
    try {
      const response = await request(
        "http://localhost:5000/api/auth",
        "POST",
        JSON.stringify(data),
        { "Content-Type": "application/json" }
      );
      set(response.message.errors[0]["msg"]);
    } catch (error) {
      console.log(error);
    }
    dispatch(registerActin());
  };

  const toLogin = async () => {
    const { nickName, email, password } = state;
    if (email === "" || password === "") {
      return set("email и password обязательны для заполнения");
    }

    const data = {
      nickName: nickName,
      email: email,
      password: password,
    };
    try {
      const response = await request(
        "http://localhost:5000/api/login",
        "POST",
        JSON.stringify(data),
        { "Content-Type": "application/json" }
      );
      if (response.message === undefined) {
        set("Операция прошла успешно");
        dispatch(registerActin());
        return;
      }
      set(response.message.errors[0]["msg"]);
    } catch (error) {
      console.log(error);
    }
    dispatch(registerActin());
  };

  return (
    <form className={styleRegistration.container}>
      <p className={styleRegistration.error}>{get}</p>
      <div>
        <div>
          {!add && (
            <InputText
              type={"text"}
              placehold={"Например: Explore23"}
              value={"Nickname"}
              createText={(e) => increaseCounter(e, nickNameActin)}
              valPol={state.nickName}
            />
          )}
        </div>
        <InputText
          type={"email"}
          placehold={"Например: explore@gmail.com"}
          value={"Email"}
          createText={(e) => increaseCounter(e, emailActin)}
          valPol={state.email}
        />
        <InputText
          type={"password"}
          placehold={"Например: 230cd_3rD"}
          value={"Password"}
          createText={(e) => increaseCounter(e, passwordActin)}
          valPol={state.password}
        />
      </div>
      <ButtonBlock set={set} registerActin={registerActin()} />
    </form>
  );
};

export default Registration;
